/* ============================================
   sound.js — Sound effects manager
   AI Prompt Enhancer
   ============================================ */

// ── State ──
let audioCtx     = null;
let soundEnabled = true;

// ── Embedded Magic MP3 ──
const magicAudio = new Audio('data:audio/mpeg;base64,');
magicAudio.volume = 0.85;

// ── Sound Toggle ──
const soundBtn = document.getElementById('soundBtn');
if (soundBtn) {
  soundBtn.addEventListener('click', () => {
    soundEnabled = !soundEnabled;
    soundBtn.textContent = soundEnabled ? '🔊' : '🔇';
    showToast(soundEnabled ? '🔊 Sound on' : '🔇 Sound off');
  });
}

// ── AudioContext (lazy init for browser autoplay policy) ──
function getCtx() {
  if (!audioCtx) {
    audioCtx = new (window.AudioContext || window.webkitAudioContext)();
  }
  return audioCtx;
}

// ── Whoosh (filtered white noise sweep) ──
function playWhoosh() {
  if (!soundEnabled) return;
  try {
    const ctx = getCtx();
    const buf = ctx.createBuffer(1, ctx.sampleRate * 0.9, ctx.sampleRate);
    const d   = buf.getChannelData(0);
    for (let i = 0; i < d.length; i++) {
      d[i] = (Math.random() * 2 - 1) * Math.pow(1 - i / d.length, 2);
    }
    const src  = ctx.createBufferSource();
    src.buffer = buf;

    const filt = ctx.createBiquadFilter();
    filt.type = 'bandpass';
    filt.frequency.value = 800;
    filt.Q.value = 0.5;

    const gain = ctx.createGain();
    gain.gain.setValueAtTime(0.18, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.9);

    src.connect(filt);
    filt.connect(gain);
    gain.connect(ctx.destination);
    src.start();
  } catch(e) { console.warn('Audio error:', e); }
}

// ── Single Chime ──
function playChime(freq, delay) {
  if (!soundEnabled) return;
  try {
    const ctx  = getCtx();
    const osc  = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = 'sine';
    osc.frequency.value = freq;

    gain.gain.setValueAtTime(0, ctx.currentTime + delay);
    gain.gain.linearRampToValueAtTime(0.12, ctx.currentTime + delay + 0.02);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + delay + 0.5);

    osc.connect(gain);
    gain.connect(ctx.destination);
    osc.start(ctx.currentTime + delay);
    osc.stop(ctx.currentTime + delay + 0.55);
  } catch(e) { console.warn('Audio error:', e); }
}

// ── Crystal Chimes (C pentatonic sparkle burst) ──
function playSparkleChimes() {
  if (!soundEnabled) return;
  [523, 659, 784, 1046].forEach((f, i) => playChime(f, i * 0.08));
}

// ── Magic MP3 (final reveal sound) ──
function playMagicSound() {
  if (!soundEnabled) return;
  try {
    magicAudio.currentTime = 0;
    magicAudio.play().catch(() => {});
  } catch(e) { console.warn('Audio error:', e); }
}